package be.schaubroeck.lpb.rkm.rekenmotor.rsz.werkbonus;

import be.schaubroeck.lpb.rkm.rekenmotor.AbstractRekenCommand;
import be.schaubroeck.lpb.rkm.rekenmotor.BedragMetCarryOver;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.WerkbonusLuik;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.BijdragePercentagesFactoryImp;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.werkbonus.basisbedrag.WerkbonusBasisBedragFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.service.BijdragePercentagesFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RkmTijdperk;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import lombok.Getter;
import org.joda.time.LocalDate;
import org.joda.time.LocalDateTime;

import java.util.Set;

@Getter
public class BerekenWerkbonus extends AbstractRekenCommand {

    private static final LocalDate START_WERKBONUS_LAGE_LONEN = new LocalDate(2000, 7, 1);
    private static final LocalDateTime START_IMPLEMENTATIE = new LocalDateTime(2004, 2, 20, 0, 0, 0);

    private final ConstantManager constantManager;
    private final WerkbonusBasisBedragFactory basisBedragFactory;
    private final WerkbonusKomtInAanmerking komtInAanMerking;
    private final WerkbonusVerdeler werkbonusVerdeler;
    private final WerkbonusCalculator werkbonusCalculator;
    private final BepaalWerkbonusOpdrachten werkbonusOpdrachten;
    private final BerekenWerkbonusOnthaalOuders werkbonusOnthaalOuders;

    public BerekenWerkbonus(ConstantManager constantManager, NlpGlobalService globalService, RkmTijdperk tijdperk) {
        this.constantManager = constantManager;
        BijdragePercentagesFactory bijdragePercentagesFactory = new BijdragePercentagesFactoryImp(constantManager, globalService);
        this.basisBedragFactory = new WerkbonusBasisBedragFactory(constantManager, globalService.getRszConstantService());
        this.komtInAanMerking = WerkbonusKomtInAanmerkingFactory.create(bijdragePercentagesFactory, globalService, tijdperk);
        this.werkbonusVerdeler = new WerkbonusVerdeler(bijdragePercentagesFactory, komtInAanMerking);
        WerkbonusReferentieLoon werkbonusReferentieLoon = new WerkbonusReferentieLoon(komtInAanMerking);
        this.werkbonusCalculator = new WerkbonusCalculator(basisBedragFactory, komtInAanMerking, werkbonusReferentieLoon);
        this.werkbonusOpdrachten = new BepaalWerkbonusOpdrachten(komtInAanMerking);
        this.werkbonusOnthaalOuders = new BerekenWerkbonusOnthaalOuders(werkbonusVerdeler, werkbonusOpdrachten);
    }

    @Override
    protected boolean execute(RekenContext context) {
        RekenTijd rekenTijd = context.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        //Dit is check voor het regressie testen. Werkbonus werd retroactief ingevoerd.
        if (rekenTijd.rekenTijdstip.isBefore(START_IMPLEMENTATIE)) {
            return CONTINUE_PROCESSING;
        }
        if (!rekenTijd.beginDatum.isBefore(START_WERKBONUS_LAGE_LONEN)) {
            werkbonusOnthaalOuders.bereken(context);
            berekenWerkbonus(context);
        }
        return CONTINUE_PROCESSING;
    }

    private void berekenWerkbonus(RekenContext context) {
        Set<Opdracht> opdrachtenWerkBonus = werkbonusOpdrachten.bepaal(context);

        berekenWerkbonusLuik(context, opdrachtenWerkBonus, WerkbonusLuik.LUIK_A);
        berekenWerkbonusLuik(context, opdrachtenWerkBonus, WerkbonusLuik.LUIK_B);
    }

    private void berekenWerkbonusLuik(RekenContext context, Set<Opdracht> opdrachtenWerkBonus, WerkbonusLuik luik) {
        RekenTijd rekenTijd = context.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        WerkbonusWerkTotaal werkTotaalLuikA = vormWerkTotaal(context, rekenTijd, opdrachtenWerkBonus, luik);
        verdeelOverOpdrachten(context, opdrachtenWerkBonus, werkTotaalLuikA, rekenTijd);
    }

    private WerkbonusWerkTotaal vormWerkTotaal(RekenContext context, RekenTijd rekenTijd, Set<Opdracht> opdrachten, WerkbonusLuik luik) {
        Money totaalBedragVermindering = vormTotaalVermindering(context, opdrachten, luik);
        Money totaalOverdracht = vormTotaalOverdracht(context, opdrachten, luik);

        Money begrenstOpForfait = basisBedragFactory.begrensOpForfait(totaalBedragVermindering, luik, rekenTijd);
        Money begrenstOverdracht = begrenstOpForfait.subtract(totaalBedragVermindering).add(totaalOverdracht).max(Money.ZERO);
        return new WerkbonusWerkTotaal(totaalBedragVermindering, totaalOverdracht, begrenstOpForfait, begrenstOverdracht, luik);

    }

    private Money vormTotaalVermindering(RekenContext context, Set<Opdracht> opdrachten, WerkbonusLuik werkbonusLuik) {
        Money totaalBedragVermindering = Money.ZERO;
        PersoonsDataManager persoonsDataManager = context.getUnchecked(RekenChainKey.PERSOONSDATA_MANAGER_KEY);
        for (Opdracht opdracht : opdrachten) {
            RekenContext opdrachtContext = context.getOpdrachtContext(opdracht);
            Money bedragVermindering = werkbonusCalculator.bereken(opdrachtContext, opdracht, werkbonusLuik);
            Money overdrachtWerkbonus = persoonsDataManager.getWerkbonusOverdracht(werkbonusLuik, opdracht);
            bedragVermindering = bedragVermindering.add(overdrachtWerkbonus);
            opdrachtContext.put(werkbonusLuik.getBedragKey(), bedragVermindering);
            totaalBedragVermindering = totaalBedragVermindering.add(bedragVermindering);
        }
        return totaalBedragVermindering;
    }

    private Money vormTotaalOverdracht(RekenContext context, Set<Opdracht> opdrachten, WerkbonusLuik werkbonusLuik) {
        Money totaalOverdracht = Money.ZERO;
        PersoonsDataManager persoonsDataManager = context.getUnchecked(RekenChainKey.PERSOONSDATA_MANAGER_KEY);
        for (Opdracht opdracht : opdrachten) {
            Money overdrachtWerkbonus = persoonsDataManager.getWerkbonusOverdracht(werkbonusLuik, opdracht);
            totaalOverdracht = totaalOverdracht.add(overdrachtWerkbonus);
        }
        return totaalOverdracht;
    }


    private void verdeelOverOpdrachten(
            RekenContext context, Set<Opdracht> opdrachten, WerkbonusWerkTotaal werkTotaalLuikA, RekenTijd rekenTijd) {
        WerkbonusCarryover werkbonusCarryover = new WerkbonusCarryover(Money.ZERO, Money.ZERO);
        for (Opdracht opdracht : opdrachten) {
            if (werkTotaalLuikA.getTotaalBedragVermindering().signum() != 0) {
                werkbonusCarryover = verdeelOverOpdracht(context, opdracht, werkTotaalLuikA, rekenTijd, werkbonusCarryover);
            }
        }
    }


    private record WerkbonusCarryover(Money werkbonus, Money overdracht) {
    }

    private WerkbonusCarryover verdeelOverOpdracht(
            RekenContext context, Opdracht opdracht, WerkbonusWerkTotaal werkTotaalLuikA, RekenTijd rekenTijd, WerkbonusCarryover carryover) {
        PersoonsDataManager persoonsDataManager = context.getUnchecked(RekenChainKey.PERSOONSDATA_MANAGER_KEY);
        RekenContext opdrachtContext = context.getOpdrachtContext(opdracht);
        BedragMetCarryOver werkbonus = herschaalWerkbonusOpBegrenzing(opdrachtContext, werkTotaalLuikA, carryover.werkbonus());
        BedragMetCarryOver overdracht = herschaalOverdrachtOpBegrenzing(persoonsDataManager, opdracht, werkTotaalLuikA, carryover.overdracht());
        werkbonusVerdeler.verdeel(werkbonus.getBedrag(), overdracht.getBedrag(), opdrachtContext, opdracht, rekenTijd, werkTotaalLuikA.getLuik());
        return new WerkbonusCarryover(werkbonus.getCarryover(), overdracht.getCarryover());
    }

    private BedragMetCarryOver herschaalWerkbonusOpBegrenzing(RekenContext opdrachtContext, WerkbonusWerkTotaal werkTotaal, Money carryover) {
        Money bedragVermindering = opdrachtContext.getMoney(werkTotaal.getLuik().getBedragKey());
        bedragVermindering = bedragVermindering.multiply(werkTotaal.getBegrenstOpForfait().divide(werkTotaal.getTotaalBedragVermindering())).add(carryover);
        BedragMetCarryOver werkbonus = BedragMetCarryOver.round(bedragVermindering, 2);
        opdrachtContext.put(werkTotaal.getLuik().getBedragKey(), werkbonus.getBedrag());
        return werkbonus;
    }

    private BedragMetCarryOver herschaalOverdrachtOpBegrenzing(
            PersoonsDataManager persoonsDataManager, Opdracht opdracht, WerkbonusWerkTotaal werkTotaal, Money carryoverOverdracht) {
        Money totaalOverdracht = werkTotaal.getTotaalOverdracht();
        if (totaalOverdracht.signum() > 0) {
            Money overdrachtWerkbonus = persoonsDataManager.getWerkbonusOverdracht(werkTotaal.getLuik(), opdracht);
            overdrachtWerkbonus = overdrachtWerkbonus.multiply(werkTotaal.getBegrenstOverdracht().divide(totaalOverdracht)).add(carryoverOverdracht);
            return BedragMetCarryOver.round(overdrachtWerkbonus, 2);
        } else {
            return new BedragMetCarryOver(Money.ZERO, carryoverOverdracht);
        }
    }


}
